    21→bool clusterSupportsHttp3AndTcpFallback(const Upstream::ClusterInfo& cluster) {
    22→  return (cluster.features() & Upstream::ClusterInfo::Features::HTTP3) &&
    23→         // USE_ALPN is only set when a TCP pool is also configured. Such cluster supports TCP
    24→         // fallback.
    25→         (cluster.features() & Upstream::ClusterInfo::Features::USE_ALPN);
    26→}
    27→
    28→std::unique_ptr<RetryStateImpl>
    29→RetryStateImpl::create(const RetryPolicy& route_policy, Http::RequestHeaderMap& request_headers,
    30→                       const Upstream::ClusterInfo& cluster, const VirtualCluster* vcluster,
    31→                       RouteStatsContextOptRef route_stats_context,
    32→                       Server::Configuration::CommonFactoryContext& context,
    33→                       Event::Dispatcher& dispatcher, Upstream::ResourcePriority priority) {
    34→  std::unique_ptr<RetryStateImpl> ret;
    35→
    36→  // We short circuit here and do not bother with an allocation if there is no chance we will retry.
    37→  // But for HTTP/3 0-RTT safe requests, which can be rejected because they are sent too early(425
    38→  // response code), we want to give them a chance to retry as normal requests even though the retry
    39→  // policy doesn't specify it. So always allocate retry state object.
    40→  if (request_headers.EnvoyRetryOn() || request_headers.EnvoyRetryGrpcOn() ||
    41→      route_policy.retryOn()) {
    42→    ret.reset(new RetryStateImpl(route_policy, request_headers, cluster, vcluster,
    43→                                 route_stats_context, context, dispatcher, priority, false));
    44→  } else if ((cluster.features() & Upstream::ClusterInfo::Features::HTTP3) &&
    45→             Http::Utility::isSafeRequest(request_headers)) {
    46→    ret.reset(new RetryStateImpl(route_policy, request_headers, cluster, vcluster,
    47→                                 route_stats_context, context, dispatcher, priority, true));
    48→  }
    49→
    50→  // Consume all retry related headers to avoid them being propagated to the upstream
    51→  request_headers.removeEnvoyRetryOn();
    52→  request_headers.removeEnvoyRetryGrpcOn();
    53→  request_headers.removeEnvoyMaxRetries();
    54→  request_headers.removeEnvoyHedgeOnPerTryTimeout();
    55→  request_headers.removeEnvoyRetriableHeaderNames();
    56→  request_headers.removeEnvoyRetriableStatusCodes();
    57→  request_headers.removeEnvoyUpstreamRequestPerTryTimeoutMs();
    58→
    59→  return ret;
    60→}
    61→
    62→RetryStateImpl::RetryStateImpl(const RetryPolicy& route_policy,
    63→                               Http::RequestHeaderMap& request_headers,
    64→                               const Upstream::ClusterInfo& cluster, const VirtualCluster* vcluster,
    65→                               RouteStatsContextOptRef route_stats_context,
    66→                               Server::Configuration::CommonFactoryContext& context,
    67→                               Event::Dispatcher& dispatcher, Upstream::ResourcePriority priority,
    68→                               bool auto_configured_for_http3)
    69→    : cluster_(cluster), vcluster_(vcluster), route_stats_context_(route_stats_context),
    70→      runtime_(context.runtime()), random_(context.api().randomGenerator()),
    71→      dispatcher_(dispatcher), time_source_(context.timeSource()),
    72→      retry_host_predicates_(route_policy.retryHostPredicates()),
    73→      retry_priority_(route_policy.retryPriority()),
    74→      retriable_status_codes_(route_policy.retriableStatusCodes()),
    75→      retriable_headers_(route_policy.retriableHeaders()),
    76→      reset_headers_(route_policy.resetHeaders()),
    77→      reset_max_interval_(route_policy.resetMaxInterval()), retry_on_(route_policy.retryOn()),
    78→      retries_remaining_(route_policy.numRetries()), priority_(priority),
    79→      auto_configured_for_http3_(auto_configured_for_http3) {
    80→  if ((cluster.features() & Upstream::ClusterInfo::Features::HTTP3) &&
    81→      Http::Utility::isSafeRequest(request_headers)) {
    82→    // Because 0-RTT requests could be rejected because they are sent too early, and such requests
    83→    // should always be retried, setup retry policy for 425 response code for all potential 0-RTT
    84→    // requests even though the retry policy isn't configured to do so. Since 0-RTT safe requests
    85→    // traditionally shouldn't have body, automatically retrying them will not cause extra
    86→    // buffering. This will also enable retry if they are reset during connect.
    87→    retry_on_ |= RetryPolicy::RETRY_ON_RETRIABLE_STATUS_CODES;
    88→    retriable_status_codes_.push_back(static_cast<uint32_t>(Http::Code::TooEarly));
    89→  }
    90→  std::chrono::milliseconds base_interval(
    91→      runtime_.snapshot().getInteger("upstream.base_retry_backoff_ms", 25));
    92→  if (route_policy.baseInterval()) {
    93→    base_interval = *route_policy.baseInterval();
    94→  }
    95→
    96→  // By default, cap the max interval to 10 times the base interval to ensure reasonable back-off
    97→  // intervals.
    98→  std::chrono::milliseconds max_interval = base_interval * 10;
    99→  if (route_policy.maxInterval()) {
   100→    max_interval = *route_policy.maxInterval();
   101→  }
   102→
   103→  backoff_strategy_ = std::make_unique<JitteredExponentialBackOffStrategy>(
   104→      base_interval.count(), max_interval.count(), random_);
   105→  host_selection_max_attempts_ = route_policy.hostSelectionMaxAttempts();
   106→
   107→  // Merge in the headers.
   108→  if (request_headers.EnvoyRetryOn()) {
   109→    retry_on_ |= parseRetryOn(request_headers.getEnvoyRetryOnValue()).first;
   110→  }
   111→  if (request_headers.EnvoyRetryGrpcOn()) {
   112→    retry_on_ |= parseRetryGrpcOn(request_headers.getEnvoyRetryGrpcOnValue()).first;
   113→  }
   114→
   115→  const auto& retriable_request_headers = route_policy.retriableRequestHeaders();
   116→  if (!retriable_request_headers.empty()) {
   117→    // If this route limits retries by request headers, make sure there is a match.
   118→    bool request_header_match = false;
   119→    for (const auto& retriable_header : retriable_request_headers) {
   120→      if (retriable_header->matchesHeaders(request_headers)) {
   121→        request_header_match = true;
   122→        break;
   123→      }
   124→    }
   125→
   126→    if (!request_header_match) {
   127→      retry_on_ = 0;
   128→    }
   129→  }
   130→  if (retry_on_ != 0 && request_headers.EnvoyMaxRetries()) {
   131→    uint64_t temp;
   132→    if (absl::SimpleAtoi(request_headers.getEnvoyMaxRetriesValue(), &temp)) {
   133→      // The max retries header takes precedence if set.
   134→      retries_remaining_ = temp;
   135→    }
   136→  }
   137→
   138→  if (request_headers.EnvoyRetriableStatusCodes()) {
   139→    for (const auto& code :
   140→         StringUtil::splitToken(request_headers.getEnvoyRetriableStatusCodesValue(), ",")) {
   141→      unsigned int out;
   142→      if (absl::SimpleAtoi(code, &out)) {
   143→        retriable_status_codes_.emplace_back(out);
   144→      }
   145→    }
   146→  }
   147→
   148→  if (request_headers.EnvoyRetriableHeaderNames()) {
   149→    // Retriable headers in the configuration are specified via HeaderMatcher.
   150→    // Giving the same flexibility via request header would require the user
   151→    // to provide HeaderMatcher serialized into a string. To avoid this extra
   152→    // complexity we only support name-only header matchers via request
   153→    // header. Anything more sophisticated needs to be provided via config.
   154→    for (const auto& header_name : StringUtil::splitToken(
   155→             request_headers.EnvoyRetriableHeaderNames()->value().getStringView(), ",")) {
   156→      envoy::config::route::v3::HeaderMatcher header_matcher;
   157→      header_matcher.set_name(std::string(absl::StripAsciiWhitespace(header_name)));
   158→      retriable_headers_.emplace_back(
   159→          Http::HeaderUtility::createHeaderData(header_matcher, context));
   160→    }
   161→  }
   162→}
   163→
   164→RetryStateImpl::~RetryStateImpl() { resetRetry(); }
   165→
